#ifndef DATASYSTEM_CLIENT_URMA_SUCCESS_RATE_TRACKER_H
#define DATASYSTEM_CLIENT_URMA_SUCCESS_RATE_TRACKER_H
#include <atomic>
#include <cstdint>
namespace datasystem { namespace client {
class UrmaSuccessRateTracker {
public:
    struct WindowStats { uint64_t successCount; uint64_t failureCount; uint64_t totalCount; };
    UrmaSuccessRateTracker() = default;
    // Record one URMA data-plane result; returns true iff this result settles a full window
    // whose success rate is unhealthy AND the switch gate was acquired.
    bool RecordUrmaResult(bool success, uint64_t windowLengthMs, uint64_t nowMs, WindowStats *windowStats = nullptr);
    void FinishSwitchAttempt(bool success, uint64_t nowMs);
    void ResetWindow();
    bool IsSwitchInProgress() const;
    uint32_t GetBackoffLevel() const;
private:
    struct WindowSnapshot { uint64_t successCount; uint64_t failureCount; };
    bool ShouldTriggerSwitch(const WindowSnapshot &snapshot, uint64_t nowMs);
    static bool IsUnhealthy(const WindowSnapshot &snapshot, double successRateRatio);
    void RecordInCurrentWindow(bool success);
    static constexpr uint64_t WINDOW_NOT_STARTED = 0;
    std::atomic<uint64_t> windowStartTimeMs_{WINDOW_NOT_STARTED};
    std::atomic<uint64_t> successCount_{0};
    std::atomic<uint64_t> failureCount_{0};
    std::atomic<bool> switchInProgress_{false};
    std::atomic<uint64_t> nextAllowedSwitchTimeMs_{0};
    std::atomic<uint32_t> backoffLevel_{0};
};
}}  // namespace
#endif

#include "datasystem/client/urma_success_rate_tracker.h"
#include "datasystem/common/flags/flags.h"
DS_DECLARE_double(urma_failover_success_rate_ratio);
DS_DECLARE_uint32(urma_failover_min_sample_count);
namespace datasystem { namespace client {
namespace {
constexpr uint64_t BACKOFF_INTERVALS_MS[] = { 1000, 2000, 4000, 8000, 10000 };
constexpr uint32_t MAX_BACKOFF_LEVEL = sizeof(BACKOFF_INTERVALS_MS) / sizeof(BACKOFF_INTERVALS_MS[0]) - 1;
}
bool UrmaSuccessRateTracker::RecordUrmaResult(bool success, uint64_t windowLengthMs, uint64_t nowMs,
                                              WindowStats *windowStats) {
    if (FLAGS_urma_failover_success_rate_ratio <= 0.0 || windowLengthMs == 0) { ResetWindow(); return false; }
    while (true) {
        uint64_t start = windowStartTimeMs_.load(std::memory_order_acquire);
        if (start == WINDOW_NOT_STARTED) {
            if (!windowStartTimeMs_.compare_exchange_strong(start, nowMs, std::memory_order_acq_rel)) continue;
            RecordInCurrentWindow(success); return false;
        }
        if (nowMs - start < windowLengthMs) { RecordInCurrentWindow(success); return false; }
        if (!windowStartTimeMs_.compare_exchange_strong(start, nowMs, std::memory_order_acq_rel)) continue;
        WindowSnapshot snapshot{ successCount_.exchange(0, std::memory_order_acq_rel),
                                 failureCount_.exchange(0, std::memory_order_acq_rel) };
        RecordInCurrentWindow(success);
        return ShouldTriggerSwitch(snapshot, nowMs);
    }
}
bool UrmaSuccessRateTracker::ShouldTriggerSwitch(const WindowSnapshot &snapshot, uint64_t nowMs) {
    uint64_t total = snapshot.successCount + snapshot.failureCount;
    if (total < FLAGS_urma_failover_min_sample_count) return false;
    if (!IsUnhealthy(snapshot, FLAGS_urma_failover_success_rate_ratio)) {
        backoffLevel_.store(0, std::memory_order_release);
        nextAllowedSwitchTimeMs_.store(0, std::memory_order_release); return false;
    }
    if (nowMs < nextAllowedSwitchTimeMs_.load(std::memory_order_acquire)) return false;
    bool expected = false;
    return switchInProgress_.compare_exchange_strong(expected, true, std::memory_order_acq_rel);
}
bool UrmaSuccessRateTracker::IsUnhealthy(const WindowSnapshot &s, double ratio) {
    uint64_t total = s.successCount + s.failureCount;
    return static_cast<double>(s.successCount) < static_cast<double>(total) * ratio;
}
}}  // namespace

